export const camelToTitleCase = (value?: string) => {
    if (!value || !value?.length) return value;
    return value
        .replace(/([a-z])([A-Z])/g, "$1 $2")
        .replace(/([A-Z])([A-Z][a-z])/g, "$1 $2")
        .replace(/_/g, " ")
        .replace(/\s+/g, " ")
        .trim()
        .replace(/\b\w/g, (char) => char.toUpperCase());
};

export const isVideo = (url: string) => {
    const videoExtensions = [".mp4", ".webm", ".avi", ".mov", ".mkv"];
    return videoExtensions.some((ext) => url.toLowerCase().endsWith(ext));
};

export const short = (value?: string, options?: { length?: number; ellipsis?: string; front?: boolean; back?: boolean }) => {
    if (!value) return;
    const length = options?.length || 6;
    const ellipsis = options?.ellipsis || " ... ";
    const front = options?.front;
    const back = options?.back;
    return (
        (front || !back ? value?.substring(0, value?.startsWith("0x") ? length + 2 : length) : "") +
        (front || back ? "" : ellipsis) +
        (!front || back ? value?.substring(value?.length - length, value?.length) : "")
    );
};

export const site = (value?: string) => {
    if (!value || value === "") return { url: undefined, origin: undefined, host: undefined };

    const url = `${value}`.trim();
    if (!url) return { url: undefined, origin: undefined, host: undefined };

    const format = (target: URL) => ({
        url,
        origin: target.origin?.toLowerCase() || url.toLowerCase(),
        host: target.host?.toLowerCase() || target.hostname?.toLowerCase() || url.toLowerCase(),
    });

    try {
        return format(new URL(url));
    } catch {
        try {
            return format(new URL(`https://${url}`));
        } catch {
            return {
                url,
                origin: url.toLowerCase(),
                host: url.replace(/^https?:\/\//i, "").toLowerCase(),
            };
        }
    }
};

