export const valid = {
    ...sdkValid,
    tx: (...tx: ({ [x: string]: string | bigint | undefined } | undefined)[]) => {
        if (!tx || tx === undefined || tx === null) return false;
        return enable(...tx.map((item) => !!sdkTransactionRequest(item)));
    },
};

export const transactionRequest = sdkTransactionRequest;

export const hex = {
    toBytes: (value: string) => {
        const bytes: number[] = [];
        value = value.replace(/[^0-9A-Fa-f]/g, "");
        for (let i = 0; i < value.length; i += 2) {
            const byte = parseInt(value.substring(i, 2), 16);
            if (!isNaN(byte)) bytes.push(byte);
        }
        return bytes;
    },
    toString: (value: string) => {
        if (!value || !value.length) return value;
        let data = value?.slice(64);
        if (data.length % 2 !== 0) data = "0" + data;
        return Buffer.from(data, "hex")
            .toString("utf8")
            .replace(/[\x00\u0000]+/g, "")
            .trim();
    },
    toNumber: (value: string) => {
        const result = Number(value);
        return isNaN(result) ? null : result;
    },
};

export const bigInt = {
    toHex: (value: BigInt): string => {
        return "0x" + value.toString(16);
    },
};

export const base64 = {
    toJson: (value: string): any => {
        try {
            value = value?.split(",")?.[1]?.replace(/[^A-Za-z0-9+/=]/g, "");
            return JSON.parse(
                new TextDecoder().decode(
                    Uint8Array.from(atob(value?.padEnd(value?.length + ((4 - (value?.length % 4)) % 4), "=")), (char) => char.charCodeAt(0)),
                ),
            );
        } catch {
            return;
        }
    },
};

export const bundle = (value?: string): { createdAt?: number; info?: BackupBundleInfo } | undefined => {
    if (!value || value.trim() === "") return;

    const data = sdkParse(value);
    if (!data || typeof data !== "object" || data?.schema !== 1 || data?.kind !== "coinmeca.wallet.backup") return;

    const info =
        data?.info &&
        typeof data.info === "object" &&
        typeof data.info.accounts === "number" &&
        typeof data.info.generated === "number" &&
        typeof data.info.imported === "number"
            ? {
                  accounts: data.info.accounts,
                  generated: data.info.generated,
                  imported: data.info.imported,
              }
            : undefined;

    return {
        createdAt: typeof data?.createdAt === "number" ? data.createdAt : undefined,
        info,
    };
};

export const sanitizeBigIntToHex = (obj: any): any => {
    if (typeof obj === "bigint") {
        return bigInt.toHex(obj);
    } else if (Array.isArray(obj)) {
        return obj.map(sanitizeBigIntToHex);
    } else if (typeof obj === "object" && obj !== null) {
        return Object.fromEntries(Object.entries(obj).map(([key, value]) => [key, sanitizeBigIntToHex(value)]));
    }
    return obj;
};

